CREATE TABLE `data_wisata` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `nama_wisata` varchar(150) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Nama destinasi wisata',
  `kategori` varchar(60) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'alam | budaya | edukasi | kuliner | belanja | religi | taman',
  `alamat` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `kecamatan` varchar(80) COLLATE utf8mb4_unicode_ci NOT NULL,
  `kota` varchar(80) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'Bandung',
  `provinsi` varchar(80) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'Jawa Barat',
  `latitude` decimal(10,7) DEFAULT NULL,
  `longitude` decimal(10,7) DEFAULT NULL,
  `tiket_dewasa` int unsigned NOT NULL DEFAULT '0' COMMENT 'Harga tiket dewasa (Rp)',
  `tiket_anak` int unsigned NOT NULL DEFAULT '0' COMMENT 'Harga tiket anak (Rp)',
  `hari_buka` varchar(120) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'Setiap hari',
  `jam_buka` varchar(60) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '08:00',
  `jam_tutup` varchar(60) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '17:00',
  `fasilitas` text COLLATE utf8mb4_unicode_ci COMMENT 'Koma-separated list fasilitas',
  `deskripsi` text COLLATE utf8mb4_unicode_ci,
  `is_active` tinyint(1) NOT NULL DEFAULT '1',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_kategori` (`kategori`),
  KEY `idx_kecamatan` (`kecamatan`),
  KEY `idx_is_active` (`is_active`)
) ENGINE=InnoDB AUTO_INCREMENT=131 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Data destinasi wisata Bandung dan sekitarnya';
